451→/**
452→ * Creates a deterministic fake embedding vector for testing.
453→ * Uses a seed to produce a reproducible 1536-dimension unit vector.
454→ * Identical seeds produce identical embeddings (cosine similarity = 1.0).
455→ */
456→export function fakeLearningEmbedding(seed: number): number[] {
457→  const dimension = 1536;
458→  const embedding = new Array<number>(dimension);
459→  // Simple deterministic pseudo-random based on seed
460→  let state = seed;
461→  for (let i = 0; i < dimension; i++) {
462→    state = ((state * 1103515245 + 12345) & 0x7fffffff);
463→    embedding[i] = (state / 0x7fffffff) * 2 - 1;
464→  }
465→  // Normalize to unit vector
466→  const magnitude = Math.sqrt(embedding.reduce((sum, v) => sum + v * v, 0));
467→  for (let i = 0; i < dimension; i++) {
468→    embedding[i] = embedding[i] / magnitude;
469→  }
470→  return embedding;
471→}
