  1→/**
  2→ * Graph scan: periodic workspace-wide analysis for contradictions and anomalies.
  3→ *
  4→ * Pure query functions that gather scan signals from the workspace graph,
  5→ * then delegate to the observer agent for contradiction analysis.
  6→ *
  7→ * Scan types:
  8→ *   1. Decision-implementation contradictions: confirmed decisions vs completed tasks
  9→ *   2. Stale blocked tasks: tasks blocked longer than threshold (14 days)
 10→ */
 11→
 12→import { RecordId, type Surreal } from "surrealdb";
 13→import type { LanguageModel } from "ai";
 14→import { createObservation, listWorkspaceOpenObservations, type ObserveTargetRecord } from "../observation/queries";
 15→import { logInfo } from "../http/observability";
 16→import { detectContradictions, evaluateAnomalies, synthesizePatterns, type Anomaly, type AnomalyCandidate } from "./llm-synthesis";
 17→import { parseEntityRef } from "./evidence-validator";
 18→
 19→// ---------------------------------------------------------------------------
 20→// Types
 21→// ---------------------------------------------------------------------------
 22→
 23→export type ConfirmedDecision = {
 24→  id: RecordId<"decision">;
 25→  summary: string;
 26→  rationale?: string;
 27→};
 28→
 29→export type CompletedTask = {
 30→  id: RecordId<"task">;
 31→  title: string;
 32→  description?: string;
 33→};
 34→
 35→export type StaleBlockedTask = {
 36→  id: RecordId<"task">;
 37→  title: string;
 38→  description?: string;
 39→  updated_at: string | Date;
 40→  daysBlocked: number;
 41→};
 42→
 43→export type StatusDriftTask = {
 44→  id: RecordId<"task">;
 45→  title: string;
 46→  status: string;
 47→  dependency: {
 48→    id: RecordId<"task">;
 49→    title: string;
 50→    status: string;
 51→  };
 52→};
 53→
 54→export type GraphScanResult = {
 55→  contradictions_found: number;
 56→  stale_blocked_found: number;
 57→  status_drift_found: number;
 58→  observations_created: number;
 59→  llm_filtered_count: number;
 60→};
 61→
 62→// ---------------------------------------------------------------------------
 63→// Configuration
 64→// ---------------------------------------------------------------------------
 65→
 66→const STALE_BLOCKED_THRESHOLD_DAYS = 14;
 67→
 68→// ---------------------------------------------------------------------------
 69→// Graph queries (pure data gathering)
 70→// ---------------------------------------------------------------------------
 71→
 72→async function queryConfirmedDecisions(
 73→  surreal: Surreal,
 74→  workspaceRecord: RecordId<"workspace", string>,
 75→): Promise<ConfirmedDecision[]> {
 76→  const [rows] = await surreal.query<[ConfirmedDecision[]]>(
 77→    `SELECT id, summary, rationale, created_at FROM decision
 78→     WHERE workspace = $ws AND status = "confirmed"
 79→     ORDER BY created_at DESC
 80→     LIMIT 50;`,
 81→    { ws: workspaceRecord },
 82→  );
 83→  return rows ?? [];
 84→}
 85→
 86→async function queryCompletedTasks(
 87→  surreal: Surreal,
 88→  workspaceRecord: RecordId<"workspace", string>,
 89→): Promise<CompletedTask[]> {
 90→  const [rows] = await surreal.query<[CompletedTask[]]>(
 91→    `SELECT id, title, description, updated_at FROM task
 92→     WHERE workspace = $ws AND status IN ["completed", "done"]
 93→     ORDER BY updated_at DESC
 94→     LIMIT 50;`,
 95→    { ws: workspaceRecord },
 96→  );
 97→  return rows ?? [];
 98→}
 99→
100→async function queryStaleBlockedTasks(
101→  surreal: Surreal,
102→  workspaceRecord: RecordId<"workspace", string>,
103→): Promise<StaleBlockedTask[]> {
104→  const thresholdDate = new Date(
105→    Date.now() - STALE_BLOCKED_THRESHOLD_DAYS * 24 * 60 * 60 * 1000,
106→  );
107→
108→  const [rows] = await surreal.query<
109→    [Array<{ id: RecordId<"task">; title: string; description?: string; updated_at: string }>]
110→  >(
111→    `SELECT id, title, description, updated_at FROM task
112→     WHERE workspace = $ws
113→       AND status = "blocked"
114→       AND updated_at < $threshold
115→     ORDER BY updated_at ASC
116→     LIMIT 50;`,
117→    { ws: workspaceRecord, threshold: thresholdDate },
118→  );
119→
120→  return (rows ?? []).map((row) => {
121→    const updatedAt = new Date(row.updated_at);
122→    const daysBlocked = Math.floor(
123→      (Date.now() - updatedAt.getTime()) / (24 * 60 * 60 * 1000),
124→    );
125→    return { ...row, daysBlocked };
126→  });
127→}
128→
129→async function queryStatusDriftTasks(
130→  surreal: Surreal,
131→  workspaceRecord: RecordId<"workspace", string>,
132→): Promise<StatusDriftTask[]> {
133→  // Two-step approach: first find completed tasks with dependencies,
134→  // then filter for incomplete dependencies in application code
135→  const [rows] = await surreal.query<[Array<{
136→    id: RecordId<"task">;
137→    title: string;
138→    status: string;
139→    dep_ids: RecordId<"task">[];
140→    dep_titles: string[];
141→    dep_statuses: string[];
142→  }>]>(
143→    `SELECT
144→       id, title, status,
145→       ->depends_on->task.id AS dep_ids,
146→       ->depends_on->task.title AS dep_titles,
147→       ->depends_on->task.status AS dep_statuses
148→     FROM task
149→     WHERE workspace = $ws
150→       AND status IN ["completed", "done"]
151→       AND array::len(->depends_on->task) > 0
152→     LIMIT 50;`,
153→    { ws: workspaceRecord },
154→  );
155→
156→  return (rows ?? []).flatMap((row) => {
157→    const depIds = row.dep_ids ?? [];
158→    const depTitles = row.dep_titles ?? [];
159→    const depStatuses = row.dep_statuses ?? [];
160→
161→    const drifts: StatusDriftTask[] = [];
162→    for (let i = 0; i < depIds.length; i++) {
163→      const depStatus = depStatuses[i];
164→      if (depStatus !== "completed" && depStatus !== "done") {
165→        drifts.push({
166→          id: row.id,
167→          title: row.title,
168→          status: row.status,
169→          dependency: {
170→            id: depIds[i],
171→            title: depTitles[i],
172→            status: depStatus,
173→          },
174→        });
175→      }
176→    }
177→    return drifts;
178→  });
179→}
180→
181→// ---------------------------------------------------------------------------
182→// Entity-level deduplication query
183→// ---------------------------------------------------------------------------
184→
185→/**
186→ * Queries existing open observer observations linked to a specific entity.
187→ * Used for entity-level dedup -- if the observer already has an open observation
188→ * on this entity, we skip creating another.
189→ */
190→// Static query map: one pre-built query string per allowed table, eliminating
191→// dynamic interpolation at the call site (prevents SurrealQL injection).
192→const OBSERVER_DEDUP_QUERIES: Record<string, string> = Object.fromEntries(
193→  ["project", "feature", "task", "decision", "question", "intent", "git_commit", "observation"].map(
194→    (table) => [
195→      table,
196→      `SELECT text, severity, status FROM observation
197→       WHERE workspace = $ws
198→         AND source_agent = "observer_agent"
199→         AND status IN ["open", "acknowledged"]
200→         AND ->observes->${table}.id CONTAINS $entity
201→       LIMIT 20;`,
202→    ],
203→  ),
204→);
205→
206→export async function queryExistingObserverObservationsForEntity(
207→  surreal: Surreal,
208→  workspaceRecord: RecordId<"workspace", string>,
209→  entityRecord: RecordId<string, string>,
210→): Promise<Array<{ text: string; severity: string; status: string }>> {
211→  const query = OBSERVER_DEDUP_QUERIES[entityRecord.table.name];
212→  if (!query) {
213→    throw new Error(`Invalid entity table for observer dedup query: ${entityRecord.table.name}`);
214→  }
215→
216→  const [rows] = await surreal.query<[Array<{ text: string; severity: string; status: string }>]>(
217→    query,
218→    { ws: workspaceRecord, entity: entityRecord },
219→  );
220→  return rows ?? [];
221→}
222→
223→// ---------------------------------------------------------------------------
224→// Deduplication
225→// ---------------------------------------------------------------------------
226→
227→type ExistingObservation = {
228→  text: string;
229→  severity: string;
230→  status: string;
231→};
232→
233→function isAlreadyObserved(
234→  existingObservations: ExistingObservation[],
235→  newText: string,
236→  entityId?: string,
237→): boolean {
238→  const normalizedNew = newText.toLowerCase();
239→
240→  return existingObservations.some((obs) => {
241→    if (obs.status === "resolved") return false;
242→
243→    // When entity ID is available, require it to appear in the existing text
244→    // so observations about different entities are never considered duplicates
245→    if (entityId && !obs.text.toLowerCase().includes(entityId.toLowerCase())) {
246→      return false;
247→    }
248→
249→    const normalizedExisting = obs.text.toLowerCase();
250→    // Check if the core issue is already covered using a meaningful prefix
251→    const prefixLen = Math.min(80, normalizedNew.length);
252→    return (
253→      normalizedExisting.includes(normalizedNew.slice(0, prefixLen)) ||
254→      normalizedNew.includes(normalizedExisting.slice(0, prefixLen))
255→    );
256→  });
257→}
258→
259→// ---------------------------------------------------------------------------
260→// Scan orchestrator
261→// ---------------------------------------------------------------------------
262→
263→export async function runGraphScan(
264→  surreal: Surreal,
265→  workspaceRecord: RecordId<"workspace", string>,
266→  observerModel: LanguageModel,
267→): Promise<GraphScanResult> {
268→  const result: GraphScanResult = {
269→    contradictions_found: 0,
270→    stale_blocked_found: 0,
271→    status_drift_found: 0,
272→    observations_created: 0,
273→    llm_filtered_count: 0,
274→  };
275→
276→  // Load existing observations for deduplication
277→  const existingObservations = await listWorkspaceOpenObservations({
278→    surreal,
279→    workspaceRecord,
280→    limit: 100,
281→  });
282→
283→  // 1. Detect decision-implementation contradictions (LLM-based)
284→  const [decisions, completedTasks] = await Promise.all([
285→    queryConfirmedDecisions(surreal, workspaceRecord),
286→    queryCompletedTasks(surreal, workspaceRecord),
287→  ]);
288→
289→  type ContradictionPair = { decision: ConfirmedDecision; task: CompletedTask };
290→  const contradictions: ContradictionPair[] = [];
291→
292→  if (decisions.length > 0 && completedTasks.length > 0) {
293→    const decisionMap = new Map(decisions.map((d) => [d.id.id as string, d]));
294→    const taskMap = new Map(completedTasks.map((t) => [t.id.id as string, t]));
295→
296→    const detected = await detectContradictions(
297→      observerModel,
298→      decisions.map((d) => ({ id: d.id.id as string, summary: d.summary, rationale: d.rationale })),
299→      completedTasks.map((t) => ({ id: t.id.id as string, title: t.title, description: t.description })),
300→    );
301→
302→    if (detected) {
303→      for (const c of detected) {
304→        const decisionId = parseEntityRef(c.decision_ref)?.id;
305→        const taskId = parseEntityRef(c.task_ref)?.id;
306→        const decision = decisionId ? decisionMap.get(decisionId) : undefined;
307→        const task = taskId ? taskMap.get(taskId) : undefined;
308→        if (decision && task) contradictions.push({ decision, task });
309→      }
310→    }
311→  }
312→
313→  result.contradictions_found = contradictions.length;
314→
315→  for (const { decision, task } of contradictions) {
316→    // Entity-level dedup: check if observer already has an open observation on this decision
317→    const existingForDecision = await queryExistingObserverObservationsForEntity(
318→      surreal, workspaceRecord,
319→      decision.id as RecordId<string, string>,
320→    );
321→
322→    const observationText =
323→      `Contradiction detected: Decision "${decision.summary}" conflicts with completed task "${task.title}". ` +
324→      `The task appears to implement an approach that contradicts the confirmed decision.`;
325→
326→    if (existingForDecision.length > 0 || isAlreadyObserved(existingObservations, observationText, decision.id.id as string)) {
327→      logInfo("observer.scan.dedup", "Skipping duplicate contradiction observation", {
328→        decisionId: decision.id.id,
329→        taskId: task.id.id,
330→      });
331→      continue;
332→    }
333→
334→    const now = new Date();
335→    await createObservation({
336→      surreal,
337→      workspaceRecord,
338→      text: observationText,
339→      severity: "conflict",
340→      sourceAgent: "observer_agent",
341→      observationType: "contradiction",
342→      now,
343→      relatedRecords: [
344→        decision.id as RecordId<"project" | "feature" | "task" | "decision" | "question", string>,
345→        task.id as RecordId<"project" | "feature" | "task" | "decision" | "question", string>,
346→      ],
347→    });
348→
349→    result.observations_created += 1;
350→  }
351→
352→  // 2. Detect stale blocked tasks and status drift (concurrent queries)
353→  const [staleBlocked, driftTasks] = await Promise.all([
354→    queryStaleBlockedTasks(surreal, workspaceRecord),
355→    queryStatusDriftTasks(surreal, workspaceRecord),
356→  ]);
357→  result.stale_blocked_found = staleBlocked.length;
358→  result.status_drift_found = driftTasks.length;
359→
360→  // 3. LLM anomaly evaluation: filter false positives before creating observations
361→  const anomalyCandidates: AnomalyCandidate[] = [];
362→
363→  for (const task of staleBlocked) {
364→    anomalyCandidates.push({
365→      entityRef: `task:${task.id.id as string}`,
366→      type: "stale_blocked",
367→      title: task.title,
368→      description: task.description,
369→      detail: `Blocked for ${task.daysBlocked} days since ${new Date(task.updated_at).toISOString().slice(0, 10)}`,
370→    });
371→  }
372→
373→  for (const drift of driftTasks) {
374→    anomalyCandidates.push({
375→      entityRef: `task:${drift.id.id as string}`,
376→      type: "status_drift",
377→      title: drift.title,
378→      description: undefined,
379→      detail: `Marked as ${drift.status} but dependency "${drift.dependency.title}" is still ${drift.dependency.status}`,
380→    });
381→  }
382→
383→  // Build evaluation map: entityRef -> LLM verdict (fallback: all relevant with default severity)
384→  const evaluationMap = new Map<string, { relevant: boolean; reasoning: string; severity: "info" | "warning" | "conflict" }>();
385→
386→  if (anomalyCandidates.length > 0) {
387→    const evaluations = await evaluateAnomalies(observerModel, anomalyCandidates);
388→
389→    if (evaluations) {
390→      for (const ev of evaluations) {
391→        evaluationMap.set(ev.entity_ref, {
392→          relevant: ev.relevant,
393→          reasoning: ev.reasoning,
394→          severity: ev.suggested_severity,
395→        });
396→      }
397→    } else {
398→      logInfo("observer.llm.fallback", "Anomaly evaluation failed, treating all as relevant", {
399→        candidateCount: anomalyCandidates.length,
400→      });
401→    }
402→  }
403→
404→  // Create observations for stale blocked tasks (LLM-filtered)
405→  for (const task of staleBlocked) {
406→    const entityRef = `task:${task.id.id as string}`;
407→    const evaluation = evaluationMap.get(entityRef);
408→
409→    // When LLM evaluated and marked not relevant, skip
410→    if (evaluation && !evaluation.relevant) {
411→      logInfo("observer.scan.llm_filtered", "Stale-blocked task filtered by LLM as not relevant", {
412→        taskId: task.id.id,
413→        reasoning: evaluation.reasoning,
414→      });
415→      result.llm_filtered_count += 1;
416→      continue;
417→    }
418→
419→    // Entity-level dedup
420→    const existingForTask = await queryExistingObserverObservationsForEntity(
421→      surreal, workspaceRecord,
422→      task.id as RecordId<string, string>,
423→    );
424→
425→    const llmReasoning = evaluation?.reasoning;
426→    const severity = evaluation?.severity ?? "warning";
427→
428→    const observationText = llmReasoning
429→      ? `Task blocked for ${task.daysBlocked} days: "${task.title}". ${llmReasoning}`
430→      : `Task blocked for ${task.daysBlocked} days: "${task.title}". ` +
431→        `This task has been blocked since ${new Date(task.updated_at).toISOString().slice(0, 10)} ` +
432→        `(exceeds the ${STALE_BLOCKED_THRESHOLD_DAYS}-day threshold).`;
433→
434→    if (existingForTask.length > 0 || isAlreadyObserved(existingObservations, observationText, task.id.id as string)) {
435→      logInfo("observer.scan.dedup", "Skipping duplicate stale-blocked observation", {
436→        taskId: task.id.id,
437→      });
438→      continue;
439→    }
440→
441→    const now = new Date();
442→    await createObservation({
443→      surreal,
