121→export async function supersedeLearning(input: {
122→  surreal: Surreal;
123→  workspaceRecord: RecordId<"workspace", string>;
124→  oldLearningRecord: LearningRecord;
125→  newLearningRecord: LearningRecord;
126→  reason?: string;
127→  now: Date;
128→}): Promise<void> {
129→  // Validate workspace scope for old learning
130→  const oldRow = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(input.oldLearningRecord);
131→  if (!oldRow) {
132→    throw new Error(`learning not found: ${input.oldLearningRecord.id as string}`);
133→  }
134→  if ((oldRow.workspace.id as string) !== (input.workspaceRecord.id as string)) {
135→    throw new Error("learning is outside the current workspace scope");
136→  }
137→
138→  // Deactivate old learning
139→  await input.surreal.update(input.oldLearningRecord).merge({
140→    status: "superseded" satisfies LearningStatus,
141→    updated_at: input.now,
142→  });
143→
144→  // Create supersedes edge: new -> old
145→  await input.surreal
146→    .relate(input.newLearningRecord, new RecordId("supersedes", randomUUID()), input.oldLearningRecord, {
147→      superseded_at: input.now,
148→      ...(input.reason ? { reason: input.reason } : {}),
149→    })
150→    .output("after");
151→}
