361→}): Promise<void> {
362→  const row = await input.surreal.select<{
363→    status: LearningStatus;
364→    workspace: RecordId<"workspace", string>;
365→  }>(input.learningRecord);
366→
367→  if (!row) {
368→    throw new LearningNotFoundError(input.learningRecord.id as string);
369→  }
370→
371→  if ((row.workspace.id as string) !== (input.workspaceRecord.id as string)) {
372→    throw new LearningNotFoundError(input.learningRecord.id as string);
373→  }
374→
375→  if (row.status !== "active") {
376→    throw new LearningNotActiveError(row.status);
377→  }
378→
379→  const mergeData: Record<string, unknown> = {
380→    updated_at: input.now,
381→  };
382→  if (input.fields.text !== undefined) {
383→    mergeData.text = input.fields.text;
384→  }
385→  if (input.fields.priority !== undefined) {
386→    mergeData.priority = input.fields.priority;
387→  }
388→  if (input.fields.targetAgents !== undefined) {
389→    mergeData.target_agents = input.fields.targetAgents;
390→  }
391→  if (input.embedding !== undefined) {
392→    mergeData.embedding = input.embedding;
393→  }
394→
395→  await input.surreal.update(input.learningRecord).merge(mergeData);
396→}
397→
398→export class LearningNotFoundError extends Error {
399→  constructor(learningId: string) {
400→    super(`learning not found: ${learningId}`);
401→    this.name = "LearningNotFoundError";
402→  }
403→}
404→
405→export class LearningNotActiveError extends Error {
406→  readonly currentStatus: string;
407→  constructor(currentStatus: string) {
408→    super(`cannot edit a learning in status '${currentStatus}'`);
409→    this.name = "LearningNotActiveError";
410→    this.currentStatus = currentStatus;
411→  }
412→}
