  1→/**
  2→ * LLM reasoning: effect boundary for generateObject calls in verification pipeline.
  3→ *
  4→ * Each function makes a single LLM call with structured output schema.
  5→ * All calls use AbortSignal.timeout(10_000) for latency control.
  6→ * Returns undefined on any failure (timeout, rate limit, invalid output).
  7→ */
  8→
  9→import { generateObject, type LanguageModel } from "ai";
 10→import { logError, logInfo } from "../http/observability";
 11→import { llmVerdictSchema, parseLlmVerdict, peerReviewVerdictSchema, type LlmVerdict, type PeerReviewVerdict } from "./schemas";
 12→import { validateEvidenceRefs } from "./evidence-validator";
 13→import type { EntityContext } from "./context-loader";
 14→import type { VerificationResult } from "./verification-pipeline";
 15→import { OBSERVER_IDENTITY } from "../agents/observer/prompt";
 16→
 17→// ---------------------------------------------------------------------------
 18→// Verification verdict (semantic verification)
 19→// ---------------------------------------------------------------------------
 20→
 21→export async function generateVerificationVerdict(
 22→  model: LanguageModel,
 23→  context: EntityContext,
 24→  deterministicVerdict: VerificationResult,
 25→): Promise<LlmVerdict | undefined> {
 26→  const start = Date.now();
 27→
 28→  try {
 29→    const decisionsText = context.relatedDecisions.length > 0
 30→      ? context.relatedDecisions.map((d) =>
 31→          `- [${d.table_id}] (${d.status}) ${d.summary}${d.rationale ? ` — ${d.rationale}` : ""}`,
 32→        ).join("\n")
 33→      : "No related decisions found.";
 34→
 35→    const result = await generateObject({
 36→      model,
 37→      system: OBSERVER_IDENTITY,
 38→      schema: llmVerdictSchema,
 39→      prompt: `Verify whether this entity aligns with or contradicts the confirmed decisions in its project.
 40→
 41→## Entity Under Review
 42→- Type: ${context.entityTable}
 43→- ID: ${context.entityTable}:${context.entityId}
 44→- Title: ${context.entityTitle}
 45→${context.entityDescription ? `- Description: ${context.entityDescription}` : ""}
 46→${context.entityStatus ? `- Status: ${context.entityStatus}` : ""}
 47→
 48→## Confirmed Decisions in Same Project
 49→${decisionsText}
 50→
 51→## Deterministic Check Result
 52→- Verdict: ${deterministicVerdict.verdict}
 53→- Text: ${deterministicVerdict.text}
 54→
 55→## Instructions
 56→Compare the entity's title and description against each decision's summary and rationale.
 57→- "mismatch" = the entity does something a decision explicitly forbids or rules out. Be specific about which decision.
 58→- "match" = the entity's approach is consistent with all decisions.
 59→- "inconclusive" = decisions don't address what the entity does, or evidence is genuinely ambiguous.
 60→
 61→In evidence_refs, list the table:id of every entity and decision relevant to your verdict.
 62→In contradiction.claim, state what the entity does. In contradiction.reality, state what the decision requires. Set both to "none" when verdict is not mismatch.
 63→Set confidence >= 0.7 when evidence clearly supports your verdict. Use < 0.5 only when genuinely ambiguous.`,
 64→      abortSignal: AbortSignal.timeout(30_000),
 65→    });
 66→
 67→    const latencyMs = Date.now() - start;
 68→    logInfo("observer.llm.call", "LLM verification verdict generated", {
 69→      latencyMs,
 70→      verdict: result.object.verdict,
 71→      confidence: result.object.confidence,
 72→    });
 73→
 74→    const parsed = parseLlmVerdict(result.object);
 75→
 76→    // Post-validate evidence refs
 77→    const validatedRefs = validateEvidenceRefs(
 78→      parsed.evidence_refs,
 79→      context.validEntityIds,
 80→    );
 81→
 82→    return {
 83→      ...parsed,
 84→      evidence_refs: validatedRefs,
 85→    };
 86→  } catch (error) {
 87→    const latencyMs = Date.now() - start;
 88→    logError("observer.llm.error", "LLM verification verdict failed", {
 89→      error,
 90→      latencyMs,
 91→    });
 92→    return undefined;
 93→  }
 94→}
 95→
 96→// ---------------------------------------------------------------------------
 97→// Peer review verdict
 98→// ---------------------------------------------------------------------------
 99→
100→export async function generatePeerReviewVerdict(
101→  model: LanguageModel,
102→  originalText: string,
103→  originalSeverity: string,
104→  sourceAgent: string,
105→  linkedEntities: Array<{ table: string; id: string; title: string; description?: string }>,
106→): Promise<PeerReviewVerdict | undefined> {
107→  const start = Date.now();
108→
109→  try {
110→    const entitiesText = linkedEntities.length > 0
111→      ? linkedEntities.map((e) =>
112→          `- [${e.table}:${e.id}] ${e.title}${e.description ? ` — ${e.description}` : ""}`,
113→        ).join("\n")
114→      : "No linked entities.";
115→
116→    const result = await generateObject({
117→      model,
118→      system: OBSERVER_IDENTITY,
119→      schema: peerReviewVerdictSchema,
120→      prompt: `Peer-review this observation from another agent. Evaluate whether its claims are grounded in the cited evidence.
121→
122→## Observation Under Review
123→- Text: "${originalText}"
124→- Severity: ${originalSeverity}
125→- Source Agent: ${sourceAgent}
126→
127→## Cited Evidence (entities linked via observes edges)
128→${entitiesText}
129→
130→## Instructions
131→- "sound" (confidence >= 0.7) = linked entities directly support the claims.
132→- "questionable" (confidence 0.4-0.7) = partial support, some claims go beyond the evidence.
133→- "unsupported" (confidence < 0.4) = claims lack evidence or contradict linked entities.
134→
135→If no entities are linked, the observation has no cited evidence — verdict should be "unsupported" with low confidence.`,
136→      abortSignal: AbortSignal.timeout(30_000),
137→    });
138→
139→    const latencyMs = Date.now() - start;
140→    logInfo("observer.llm.peer_review", "LLM peer review verdict generated", {
141→      latencyMs,
142→      verdict: result.object.verdict,
143→      confidence: result.object.confidence,
144→    });
145→
146→    return result.object;
147→  } catch (error) {
148→    const latencyMs = Date.now() - start;
149→    logError("observer.llm.peer_review_error", "LLM peer review verdict failed", {
150→      error,
151→      latencyMs,
152→    });
153→    return undefined;
154→  }
155→}
