  1→/**
  2→ * Observer agent: verifies entity state changes and surfaces observations.
  3→ *
  4→ * Owns the full verification pipeline: deterministic + LLM reasoning.
  5→ * Called by observer-route.ts (HTTP adapter) for each entity event.
  6→ *
  7→ * Pipeline: receive event -> gather signals -> deterministic verdict
  8→ *           -> (optional) LLM reasoning -> persist observation
  9→ */
 10→
 11→import { RecordId, type Surreal } from "surrealdb";
 12→import type { LanguageModel } from "ai";
 13→import { createObservation, type ObserveTargetRecord } from "../../observation/queries";
 14→import { queryExistingObserverObservationsForEntity } from "../../observer/graph-scan";
 15→import { logInfo } from "../../http/observability";
 16→import { gatherTaskSignals } from "../../observer/external-signals";
 17→import { checkCiStatus } from "../../observer/external-signals";
 18→import {
 19→  compareTaskCompletion,
 20→  compareIntentCompletion,
 21→  compareCommitStatus,
 22→  compareDecisionConfirmation,
 23→  compareObservationPeerReview,
 24→  shouldSkipLlm,
 25→  applyLlmVerdict,
 26→  type VerificationResult,
 27→  type IntentSignals,
 28→  type DecisionSignals,
 29→  type ObservationPeerReviewSignals,
 30→} from "../../observer/verification-pipeline";
 31→import { buildEntityContext } from "../../observer/context-loader";
 32→import { generateVerificationVerdict, generatePeerReviewVerdict } from "../../observer/llm-reasoning";
 33→import { parseEntityRef } from "../../observer/evidence-validator";
 34→
 35→// ---------------------------------------------------------------------------
 36→// Types
 37→// ---------------------------------------------------------------------------
 38→
 39→export type ObserverVerdict = "match" | "mismatch" | "inconclusive";
 40→
 41→export type ObserverAgentOutput = {
 42→  observations_created: number;
 43→  verdict: ObserverVerdict;
 44→  evidence: string[];
 45→};
 46→
 47→export type ObserverAgentInput = {
 48→  surreal: Surreal;
 49→  workspaceRecord: RecordId<"workspace", string>;
 50→  entityTable: string;
 51→  entityId: string;
 52→  entityBody?: Record<string, unknown>;
 53→  observerModel?: LanguageModel;
 54→};
 55→
 56→// ---------------------------------------------------------------------------
 57→// Agent entry point
 58→// ---------------------------------------------------------------------------
 59→
 60→export async function runObserverAgent(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
 61→  const { entityTable } = input;
 62→
 63→  switch (entityTable) {
 64→    case "task":
 65→      return verifyTask(input);
 66→    case "intent":
 67→      return verifyIntent(input);
 68→    case "git_commit":
 69→      return verifyCommit(input);
 70→    case "decision":
 71→      return verifyDecision(input);
 72→    case "observation":
 73→      return peerReviewObservation(input);
 74→    default:
 75→      return {
 76→        observations_created: 0,
 77→        verdict: "inconclusive",
 78→        evidence: [`Entity type '${entityTable}' verification not yet implemented`],
 79→      };
 80→  }
 81→}
 82→
 83→// ---------------------------------------------------------------------------
 84→// Task verification (deterministic + LLM)
 85→// ---------------------------------------------------------------------------
 86→
 87→async function verifyTask(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
 88→  const { surreal, workspaceRecord, entityId: taskId, entityBody: body, observerModel } = input;
 89→  const taskRecord = new RecordId("task", taskId);
 90→  const evidence: string[] = [];
 91→
 92→  // Deterministic: gather external signals (commits, CI)
 93→  const signalsResult = await gatherTaskSignals(surreal, taskId);
 94→  evidence.push(`Commits found: ${signalsResult.hasCommits}`);
 95→  evidence.push(`Signal count: ${signalsResult.signals.length}`);
 96→
 97→  const deterministicResult = compareTaskCompletion(signalsResult);
 98→  evidence.push(`Verdict: ${deterministicResult.verdict}`);
 99→  evidence.push(deterministicResult.text);
100→
101→  // LLM reasoning path
102→  if (observerModel) {
103→    const skipDeterministic = await loadWorkspaceSkipSetting(surreal, workspaceRecord);
104→
105→    if (shouldSkipLlm(deterministicResult, skipDeterministic)) {
106→      logInfo("observer.llm.skip", "LLM skipped: deterministic match + CI passing", { taskId });
107→    } else {
108→      const context = await buildEntityContext(surreal, workspaceRecord, "task", taskId, body);
109→
110→      // Only invoke LLM when there are decisions to check against.
111→      // Without decisions, semantic verification has nothing to compare --
112→      // the deterministic CI-based verdict should stand.
113→      if (context.relatedDecisions.length === 0) {
114→        logInfo("observer.llm.skip", "LLM skipped: no related decisions to verify against", { taskId });
115→        await persistObservation(surreal, workspaceRecord, [taskRecord as ObserveTargetRecord], deterministicResult);
116→        return {
117→          observations_created: 1,
118→          verdict: deterministicResult.verdict,
119→          evidence,
120→        };
121→      }
122→
123→      const llmVerdict = await generateVerificationVerdict(observerModel, context, deterministicResult);
124→      const finalVerdict = applyLlmVerdict(deterministicResult, llmVerdict);
125→
126→      // Link contradicted decisions via observes edges
127→      const additionalRecords = extractDecisionRecords(llmVerdict?.evidence_refs);
128→
129→      await persistObservation(surreal, workspaceRecord, [taskRecord as ObserveTargetRecord, ...additionalRecords], finalVerdict);
130→
131→      return {
132→        observations_created: 1,
133→        verdict: finalVerdict.verdict,
134→        evidence,
135→      };
136→    }
137→  }
138→
139→  // Deterministic-only path
140→  await persistObservation(surreal, workspaceRecord, [taskRecord as ObserveTargetRecord], deterministicResult);
141→
142→  return {
143→    observations_created: 1,
144→    verdict: deterministicResult.verdict,
145→    evidence,
146→  };
147→}
148→
149→// ---------------------------------------------------------------------------
150→// Intent verification (deterministic only)
151→// ---------------------------------------------------------------------------
152→
153→async function verifyIntent(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
154→  const { surreal, workspaceRecord, entityId: intentId, entityBody: body } = input;
155→  const intentRecord = new RecordId("intent", intentId);
156→
157→  const intentSignals = await gatherIntentSignals(surreal, intentId, body);
158→  const result = compareIntentCompletion(intentSignals);
159→
160→  await persistObservation(surreal, workspaceRecord, [intentRecord as ObserveTargetRecord], result);
161→
162→  return {
163→    observations_created: 1,
164→    verdict: result.verdict,
165→    evidence: [result.text],
166→  };
167→}
