  1→/**
  2→ * LLM synthesis: effect boundary for generateObject calls in pattern synthesis pipeline.
  3→ *
  4→ * Takes anomalies from deterministic graph scan and synthesizes named patterns.
  5→ * Uses AbortSignal.timeout(10_000) for latency control.
  6→ * Returns undefined on any failure.
  7→ */
  8→
  9→import { generateObject, type LanguageModel } from "ai";
 10→import { logError, logInfo } from "../http/observability";
 11→import { anomalyEvaluationResultSchema, contradictionDetectionResultSchema, synthesisResultSchema, type AnomalyEvaluation, type DetectedContradiction, type SynthesisPattern } from "./schemas";
 12→import { OBSERVER_IDENTITY } from "../agents/observer/prompt";
 13→
 14→export type Anomaly = {
 15→  type: "contradiction" | "stale_blocked" | "status_drift";
 16→  text: string;
 17→  entityId: string;
 18→  entityTable: string;
 19→};
 20→
 21→/**
 22→ * Synthesizes anomalies into named patterns via LLM.
 23→ * Returns patterns with min 2 contributing entities, or undefined on failure.
 24→ */
 25→export async function synthesizePatterns(
 26→  model: LanguageModel,
 27→  anomalies: Anomaly[],
 28→): Promise<SynthesisPattern[] | undefined> {
 29→  if (anomalies.length === 0) return [];
 30→
 31→  const start = Date.now();
 32→
 33→  // Partition large workspaces: top 20 per type
 34→  const partitioned = partitionAnomalies(anomalies, 20);
 35→
 36→  try {
 37→    const anomaliesText = partitioned.map((a) =>
 38→      `- [${a.entityTable}:${a.entityId}] (${a.type}) ${a.text}`,
 39→    ).join("\n");
 40→
 41→    const result = await generateObject({
 42→      model,
 43→      schema: synthesisResultSchema,
 44→      prompt: `You are a pattern synthesis agent analyzing workspace anomalies to identify systemic patterns.
 45→
 46→## Anomalies Detected
 47→${anomaliesText}
 48→
 49→## Instructions
 50→Analyze these anomalies and identify higher-level patterns:
 51→- "bottleneck_decision" = single decision blocking multiple tasks
 52→- "cascade_block" = chain of blocked items
 53→- "priority_drift" = priorities inconsistent with actions
 54→- "stale_cluster" = group of stale items in same area
 55→- "contradiction_cluster" = multiple contradictions sharing a root cause
 56→
 57→Rules:
 58→- Each pattern MUST reference at least 2 contributing entities using table:id format
 59→- Only include entities from the anomalies listed above
 60→- If no meaningful patterns emerge, return an empty patterns array
 61→- Set severity to "conflict" only for active contradictions`,
 62→      abortSignal: AbortSignal.timeout(10_000),
 63→    });
 64→
 65→    const latencyMs = Date.now() - start;
 66→    logInfo("observer.llm.synthesis", "LLM pattern synthesis completed", {
 67→      latencyMs,
 68→      patternCount: result.object.patterns.length,
 69→    });
 70→
 71→    // Filter patterns with < 2 contributing entities (schema enforces min 2, but defense in depth)
 72→    return result.object.patterns.filter((p) => p.contributing_entities.length >= 2);
 73→  } catch (error) {
 74→    const latencyMs = Date.now() - start;
 75→    logError("observer.llm.synthesis_error", "LLM pattern synthesis failed", {
 76→      error,
 77→      latencyMs,
 78→    });
 79→    return undefined;
 80→  }
 81→}
