      severity: "info",
    });

    // When the graph scan runs
    const response = await triggerDiagnosticPipeline(
      baseUrl,
      workspaceId,
      user.headers,
    );

    // Then the scan completes regardless of model availability
    expect(response.ok).toBe(true);
  }, 120_000);
});

